"use strict";parserFactory.register("bnatranslations.com",()=>new BnatranslationsParser);class BnatranslationsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".elementor-text-editor a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("article .post__content .elementor-widget-container")}extractTitleImpl(e){return e.querySelector(".page__title h1")}findChapterTitle(e){return e.querySelector(".page__title h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".elementor-widget-container")}preprocessRawDom(e){util.removeChildElementsMatchingSelector(e,".elementor-button-wrapper");let t=[...e.querySelectorAll("article .post__content .elementor-widget-container")],r=t[0],n=0;for(;++n<t.length;){if(null!=t[n].querySelector(".wordpress-follow-button"))break;util.moveChildElements(t[n],r),t[n].remove()}}}